const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const ClockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PartSearchScreen: React.FC<PartSearchScreenProps> = (props) => {
  const { 
    currentUser, currentUserRole, onLogout, tasks, onAddTask, onUpdateTask, roles, permissions,
    notifications, onClearNotification, installPrompt, onInstallApp, parts, workplaces,
    onToggleTask, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleBlock, onToggleManualBlock, onMarkAsIncorrect, onAddNote, onReleaseTask, missingReasons,
    users,
    onApprovePartRequest, onRejectPartRequest,
    onArchiveTasks,
    breakSchedules,
    bomItems, bomRequests, onApproveBOMRequest, onRejectBOMRequest,
    onAddRole, onDeleteRole, onUpdatePermission, onVerifyAdminPassword,
    systemConfig, onUpdateSystemConfig,
    dbLoadWarning
  } = props;

  const { t, language, setLanguage } = useLanguage();

  const [entryMode, setEntryMode] = useState<'production' | 'logistics'>('production');
  const [selectedPart, setSelectedPart] = useState<DBItem | null>(null);
  const [selectedWorkplace, setSelectedWorkplace] = useState<string | null>(null);
  const [logisticsRef, setLogisticsRef] = useState('');
  const [logisticsOp, setLogisticsOp] = useState('');
  const [quantity, setQuantity] = useState<string>('');
  const [quantityUnit, setQuantityUnit] = useState<'pcs' | 'boxes' | 'pallet'>('pcs');
  const [priority, setPriority] = useState<PriorityLevel>('NORMAL');
  const [taskSearchQuery, setTaskSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'entry' | 'tasks' | 'settings' | 'analytics' | 'bom' | 'missing' | 'logistics' | 'permissions' | 'inventory'>('entry');
  const [showSuccessMessage, setShowSuccessMessage] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);

  const [auditStartTask, setAuditStartTask] = useState<Task | null>(null);
  const [auditFinishTask, setAuditFinishTask] = useState<Task | null>(null);
  const [auditNote, setAuditNote] = useState('');

  const currentRoleId = roles.find(r => r.name === currentUserRole)?.id;
  const hasPermission = useCallback((permName: string) => {
      if (currentUserRole === 'ADMIN' && (permName === 'perm_tab_permissions' || permName === 'perm_manage_roles' || permName === 'perm_tab_settings')) {
          return true;
      }
      if (!currentRoleId) return false;
      return permissions.some(p => p.roleId === currentRoleId && p.permissionName === permName);
  }, [currentUserRole, currentRoleId, permissions]);

  const unfinishedTasksCount = tasks.filter(t => !t.isDone).length;
  const pendingRequestsCount = props.partRequests.length + props.bomRequests.length;

  const partNumbersList = useMemo(() => parts.map(p => p.value), [parts]);

  const isDataLoading = parts.length === 0 || workplaces.length === 0;

  const logisticsOperationsList = useMemo(() => {
      if (props.logisticsOperations && props.logisticsOperations.length > 0) {
          return props.logisticsOperations;
      }
      return [
          { id: 'op_unloading', value: t('op_unloading') },
          { id: 'op_loading', value: t('op_loading') },
          { id: 'op_putaway', value: t('op_putaway') },
          { id: 'op_move', value: t('op_move') }
      ];
  }, [props.logisticsOperations, t]);

  useEffect(() => {
      if (entryMode === 'logistics') {
          setQuantityUnit('pallet');
      } else {
          setQuantityUnit('pcs');
      }
  }, [entryMode]);

  const handleSendToTasks = () => {
    if (entryMode === 'production') {
        if (!selectedPart || !selectedWorkplace || !quantity) {
            alert(t('fill_all_fields')); 
            return;
        }
        onAddTask(selectedPart.value, selectedWorkplace, quantity, quantityUnit, priority, false);
    } else {
        if (!logisticsRef || !logisticsOp || !quantity) {
            alert(t('fill_all_fields'));
            return;
        }
        onAddTask(logisticsRef, logisticsOp, quantity, quantityUnit, priority, true);
    }

    setSelectedPart(null);
    setSelectedWorkplace(null);
    setLogisticsRef('');
    setLogisticsOp('');
    setQuantity('');
    if (entryMode === 'logistics') { setQuantityUnit('pallet'); } else { setQuantityUnit('pcs'); }
    setPriority('NORMAL'); 
    setShowSuccessMessage(true);
    setTimeout(() => setShowSuccessMessage(false), 2000);
  };

  const handleToggleFullscreen = () => {
    if (!document.fullscreenElement) {
      document.documentElement.requestFullscreen();
      setIsFullscreen(true);
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
        setIsFullscreen(false);
      }
    }
  };

  const handleAuditClick = (task: Task) => {
      if (task.isAuditInProgress) { setAuditFinishTask(task); setAuditNote(''); } else { setAuditStartTask(task); }
  };

  const handleConfirmStartAudit = () => { if (auditStartTask) { props.onStartAudit(auditStartTask.id); setAuditStartTask(null); } };
  const handleConfirmFinishAudit = (result: 'found' | 'missing', note: string) => { if (auditFinishTask && note.trim()) { props.onFinishAudit(auditFinishTask.id, result, note.trim()); setAuditFinishTask(null); } else { alert(t('fill_all_fields')); } };

  return (
    <div className="flex flex-col h-screen bg-gray-900 text-white">
      {/* Notifications ... */}
      {notifications.length > 0 && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 p-4">
              <div className="bg-gray-800 rounded-2xl max-w-2xl w-full p-8 shadow-2xl border border-gray-700 animate-fade-in">
                  <div className="flex items-center justify-between mb-6 border-b border-gray-700 pb-4">
                      <h3 className="text-3xl font-black text-teal-400 uppercase tracking-tighter">{t('alert_missing_title')}</h3>
                      <span className="bg-teal-500/20 text-teal-400 px-3 py-1 rounded-full text-xs font-bold">{notifications.length}</span>
                  </div>
                  <div className="space-y-4 max-h-[60vh] overflow-y-auto custom-scrollbar pr-2">
                      {notifications.map(notif => {
                          const isAudit = notif.reason.toUpperCase().includes('AUDIT');
                          const itemBgClass = isAudit ? "bg-amber-900/20 border-amber-800/40" : "bg-red-900/20 border-red-800/40";
                          const iconColorClass = isAudit ? "text-amber-400" : "text-red-400";
                          return (
                              <div key={notif.id} className={`${itemBgClass} border p-5 rounded-xl flex items-center justify-between gap-6 transition-all hover:bg-opacity-30`}>
                                  <div className="flex-grow min-w-0">
                                      <div className="flex items-center gap-3 mb-1">
                                          <div className={`w-2 h-2 rounded-full ${isAudit ? 'bg-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.6)]' : 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.6)]'}`}></div>
                                          <p className="font-mono font-black text-2xl text-white truncate">{notif.partNumber}</p>
                                      </div>
                                      <p className="text-lg text-gray-200 font-medium leading-tight mb-2">{notif.reason}</p>
                                      <div className="flex items-center gap-4 text-sm text-gray-500 font-bold uppercase tracking-wide">
                                          <span className={iconColorClass}>{notif.reportedBy}</span>
                                          <span className="opacity-50">•</span>
                                          <span>{new Date(notif.timestamp).toLocaleString('sk-SK', {hour:'2-digit', minute:'2-digit', day:'2-digit', month:'2-digit'})}</span>
                                      </div>
                                  </div>
                                  <button onClick={() => props.onClearNotification(notif.id)} className="flex-shrink-0 bg-gray-900/50 text-gray-400 hover:text-white p-3 rounded-xl hover:bg-gray-700 transition-all active:scale-90">
                                      <CheckCircleIcon className="w-8 h-8" />
                                  </button>
                              </div>
                          );
                      })}
                  </div>
                  <div className="mt-8 flex gap-4">
                      <button onClick={() => notifications.forEach(n => props.onClearNotification(n.id))} className="flex-1 py-4 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-black text-lg shadow-xl transition-all active:scale-[0.98] uppercase tracking-widest">{t('alert_btn_ok')}</button>
                  </div>
              </div>
          </div>
      )}

      {/* Break Banner ... */}
      {props.isBreakActive && (
        <div className="w-full px-2 sm:px-4 pt-2 z-50 bg-gray-900">
            <div className="w-full bg-red-600 text-white py-5 rounded-xl shadow-[0_0_20px_rgba(220,38,38,0.6)] flex items-center justify-center gap-4 animate-pulse border-2 border-red-400">
                <ClockIcon className="w-10 h-10 flex-shrink-0" />
                <span className="font-black text-2xl sm:text-3xl uppercase tracking-[0.2em] leading-none text-center">PREBIEHA PRESTÁVKA</span>
            </div>
        </div>
      )}

      {showSuccessMessage && (
        <div className="fixed top-24 right-6 bg-green-600 text-white px-6 py-4 rounded-xl shadow-2xl z-50 animate-bounce font-black tracking-widest">✓ {t('sent_msg')}</div>
      )}

      <AppHeader currentUser={currentUser} currentUserRole={currentUserRole} onLogout={onLogout} language={language} setLanguage={setLanguage} t={t} isFullscreen={isFullscreen} onToggleFullscreen={handleToggleFullscreen} installPrompt={installPrompt} onInstallApp={onInstallApp} hasPermission={hasPermission} />

      {isDataLoading && activeTab === 'entry' ? (
          <div className="flex-grow flex items-center justify-center bg-gray-900">
              <div className="text-center space-y-6">
                  <div className="inline-block w-14 h-14 border-4 border-teal-500 border-t-transparent rounded-full animate-spin"></div>
                  <p className="text-teal-400 font-black animate-pulse uppercase tracking-[0.2em] text-base">Synchronizujem databázu dielov...</p>
                  <p className="text-gray-600 text-sm">Toto môže chvíľu trvať pri prvom spustení.</p>
              </div>
          </div>
      ) : (
          <>
            <TabNavigator activeTab={activeTab} setActiveTab={setActiveTab} hasPermission={hasPermission} t={t} counts={{ tasks: unfinishedTasksCount, pendingRequests: pendingRequestsCount }} />

            <div className="flex-grow overflow-y-auto p-3 md:p-8 custom-scrollbar">
                <div className="max-w-7xl mx-auto w-full h-full">
                {activeTab === 'entry' && hasPermission('perm_tab_entry') && (
                    <ProductionEntry mode={entryMode} setMode={setEntryMode} selectedPart={selectedPart} setSelectedPart={setSelectedPart} selectedWorkplace={selectedWorkplace} setSelectedWorkplace={setSelectedWorkplace} logisticsRef={logisticsRef} setLogisticsRef={setLogisticsRef} logisticsOp={logisticsOp} setLogisticsOp={setLogisticsOp} quantity={quantity} setQuantity={setQuantity} quantityUnit={quantityUnit} setQuantityUnit={setQuantityUnit} priority={priority} setPriority={setPriority} parts={parts} workplaces={workplaces} logisticsOperationsList={logisticsOperationsList} t={t} language={language} hasPermission={hasPermission} handleAdd={handleSendToTasks} onRequestPart={props.onRequestPart} />
                )}
                {activeTab === 'tasks' && hasPermission('perm_tab_tasks') && (
                    <div className="animate-fade-in pb-20">
                    <div className="mb-6 flex justify-center">
                        <input type="text" value={taskSearchQuery} onChange={e => setTaskSearchQuery(e.target.value)} className="w-full max-w-lg h-12 px-6 bg-gray-800 border border-gray-700 rounded-xl text-white placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base" placeholder={t('task_search_placeholder')} />
                    </div>
                    <TaskList currentUser={currentUserRole} currentUserName={currentUser} tasks={tasks.filter(t => { const q = taskSearchQuery.toLowerCase(); return (t.partNumber && t.partNumber.toLowerCase().includes(q)) || (t.text && t.text.toLowerCase().includes(q)) || (t.workplace && t.workplace.toLowerCase().includes(q)); })} onToggleTask={onToggleTask} onEditTask={onEditTask} onDeleteTask={onDeleteTask} onToggleMissing={onToggleMissing} onSetInProgress={onSetInProgress} onToggleBlock={onToggleBlock} onToggleManualBlock={onToggleManualBlock} onMarkAsIncorrect={onMarkAsIncorrect} onAddNote={onAddNote} onReleaseTask={onReleaseTask} onAuditPart={handleAuditClick} missingReasons={missingReasons} hasPermission={hasPermission} />
                    </div>
                )}
                {/* Other tabs ... */}
                {activeTab === 'analytics' && hasPermission('perm_tab_analytics') && <AnalyticsTab tasks={tasks} onFetchArchivedTasks={props.onFetchArchivedTasks} systemBreaks={props.systemBreaks} />}
                {activeTab === 'settings' && hasPermission('perm_tab_settings') && <SettingsTab hasPermission={hasPermission} currentUserRole={currentUserRole} users={users} onAddUser={props.onAddUser} onUpdatePassword={props.onUpdatePassword} onUpdateUserRole={props.onUpdateUserRole} onDeleteUser={props.onDeleteUser} parts={parts} workplaces={workplaces} missingReasons={missingReasons} onAddPart={props.onAddPart} onBatchAddParts={props.onBatchAddParts} onDeletePart={props.onDeletePart} onDeleteAllParts={props.onDeleteAllParts} onAddWorkplace={props.onAddWorkplace} onBatchAddWorkplaces={props.onBatchAddWorkplaces} onDeleteWorkplace={props.onDeleteWorkplace} onDeleteAllWorkplaces={props.onDeleteAllWorkplaces} onAddMissingReason={props.onAddMissingReason} onDeleteMissingReason={props.onDeleteMissingReason} logisticsOperations={logisticsOperationsList} onAddLogisticsOperation={props.onAddLogisticsOperation} onDeleteLogisticsOperation={props.onDeleteLogisticsOperation} partRequests={props.partRequests} onApprovePartRequest={onApprovePartRequest} onRejectPartRequest={id => props.onRejectPartRequest(id)} onArchiveTasks={onArchiveTasks} breakSchedules={breakSchedules} onAddBreakSchedule={props.onAddBreakSchedule} onDeleteBreakSchedule={props.onDeleteBreakSchedule} bomItems={bomItems} bomRequests={bomRequests} onAddBOMItem={props.onAddBOMItem} onBatchAddBOMItems={props.onBatchAddBOMItems} onDeleteBOMItem={props.onDeleteBOMItem} onDeleteAllBOMItems={props.onDeleteAllBOMItems} onApproveBOMRequest={onApproveBOMRequest} onRejectBOMRequest={id => props.onRejectBOMRequest(id)} roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} installPrompt={installPrompt} onInstallApp={onInstallApp} systemConfig={systemConfig} onUpdateSystemConfig={onUpdateSystemConfig} dbLoadWarning={dbLoadWarning} />}
                {activeTab === 'bom' && hasPermission('perm_tab_bom') && <BOMScreen parts={parts} workplaces={workplaces} bomItems={bomItems} onAddTask={onAddTask} onRequestBOM={props.onRequestBOM} t={t} language={language} />}
                {activeTab === 'missing' && hasPermission('perm_tab_missing') && <MissingItemsTab tasks={tasks} onDeleteMissingItem={props.onDeleteMissingItem} hasPermission={hasPermission} />}
                {activeTab === 'inventory' && hasPermission('perm_tab_inventory') && <InventoryTab currentUser={currentUser} tasks={tasks} onAddTask={onAddTask} onUpdateTask={onUpdateTask} onToggleTask={onToggleTask} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} parts={partNumbersList} onRequestPart={props.onRequestPart} />}
                {activeTab === 'logistics' && hasPermission('perm_tab_logistics_center') && <LogisticsCenterTab tasks={tasks} onDeleteTask={props.onDeleteTask} hasPermission={hasPermission} />}
                {activeTab === 'permissions' && hasPermission('perm_tab_permissions') && <PermissionsTab roles={roles} permissions={permissions} onAddRole={onAddRole} onDeleteRole={onDeleteRole} onUpdatePermission={onUpdatePermission} onVerifyAdminPassword={onVerifyAdminPassword} />}
                </div>
            </div>
          </>
      )}

      {auditStartTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditStartTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white mb-6 text-center uppercase tracking-widest">{t('audit_start_title')}</h3>
                  <p className="text-gray-300 text-center mb-10 text-base leading-relaxed">{t('audit_start_desc', { part: (auditStartTask?.partNumber || '') as string })}</p>
                  <div className="flex gap-4">
                      <button onClick={() => setAuditStartTask(null)} className="flex-1 py-5 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs tracking-widest">{t('btn_cancel')}</button>
                      <button onClick={handleConfirmStartAudit} className="flex-1 py-5 bg-[#926a05] hover:bg-[#a67c06] text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest border-2 border-[#b68406]">Potvrdiť začiatok</button>
                  </div>
              </div>
          </div>,
          document.body
      )}

      {auditFinishTask && createPortal(
          <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setAuditFinishTask(null)}>
              <div className="bg-gray-800 border-2 border-[#926a05] rounded-xl shadow-2xl w-full max-w-lg p-8 relative" onClick={e => e.stopPropagation()}>
                  <h3 className="text-2xl font-black text-white mb-8 text-center uppercase tracking-widest">{t('audit_finish_title')}</h3>
                  <div className="mb-8">
                      <label className="block text-gray-400 text-xs font-black uppercase mb-3 tracking-[0.2em]">{t('audit_finish_note')}</label>
                      <textarea value={auditNote} onChange={(e) => setAuditNote(e.target.value)} className="w-full bg-gray-700 border border-gray-600 rounded-xl text-white px-5 py-4 focus:outline-none focus:ring-2 focus:ring-[#926a05] h-40 text-base font-medium placeholder-gray-500" placeholder="..." autoFocus />
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-6">
                      <button onClick={() => handleConfirmFinishAudit('found', auditNote)} disabled={!auditNote.trim()} className={`py-5 rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest flex items-center justify-center gap-2 border-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 border-gray-700 cursor-not-allowed' : 'bg-green-600 border-green-500 text-white'}`}>✅ {t('audit_found_btn')}</button>
                      <button onClick={() => handleConfirmFinishAudit('missing', auditNote)} disabled={!auditNote.trim()} className={`py-5 rounded-xl font-black transition-all shadow-xl uppercase text-xs tracking-widest flex items-center justify-center gap-2 border-2 ${!auditNote.trim() ? 'bg-gray-700 text-gray-500 border-gray-700 cursor-not-allowed' : 'bg-red-600 border-red-500 text-white'}`}>❌ {t('audit_missing_btn')}</button>
                  </div>
                  <button onClick={() => setAuditFinishTask(null)} className="w-full py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-[10px] tracking-widest">{t('btn_cancel')}</button>
              </div>
          </div>,
          document.body
      )}
    </div>
  );
};

export default PartSearchScreen;

import React, { useState, useMemo } from 'react';
import PartNumberInput from '../PartNumberInput';
import { DBItem, BOMItem, PriorityLevel } from '../../App';

interface BOMScreenProps {
  parts: DBItem[];
  workplaces: DBItem[];
  bomItems: BOMItem[];
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean) => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  t: (key: any, params?: any) => string;
  language: string;
}

const ClipboardListIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
    </svg>
);

const ActivityIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
    </svg>
);

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" />
    </svg>
);

const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const BOMScreen: React.FC<BOMScreenProps> = ({ 
  parts, 
  workplaces, 
  bomItems, 
  onAddTask, 
  onRequestBOM, 
  t, 
  language 
}) => {
  const [bomParentQuery, setBomParentQuery] = useState('');
  const [bomQuantity, setBomQuantity] = useState('');
  const [bomSelectedWorkplace, setBomSelectedWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());
  const [bomRequestStatus, setBomRequestStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [displayedBomParent, setDisplayedBomParent] = useState<string | null>(null);
  const [displayedBomQuantity, setDisplayedBomQuantity] = useState<number | null>(null);

  const handleCalculateBOM = () => {
    if (!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0) {
        alert(t('bom_invalid_input')); 
        return;
    }
    setDisplayedBomParent(bomParentQuery);
    setDisplayedBomQuantity(parseFloat(bomQuantity));
    setClickedBOMTasks(new Set());
  };

  const handleCreateBOMTask = (childPart: string, qty: number) => {
    if (!bomSelectedWorkplace) {
        alert(t('select_bom_workplace'));
        return;
    }
    onAddTask(childPart, bomSelectedWorkplace, qty.toString(), 'pcs', 'NORMAL', false);
    setClickedBOMTasks(prev => new Set(prev).add(childPart));
  };

  const handleCreateAllBOMTasks = (results: any[]) => {
      if (!bomSelectedWorkplace) {
          alert(t('select_bom_workplace'));
          return;
      }
      results.forEach(res => {
          if (!clickedBOMTasks.has(res.childPart)) {
              handleCreateBOMTask(res.childPart, res.requiredQty);
          }
      });
  };

  const handleRequestNewBOM = async () => {
      if (!bomParentQuery) return;
      setBomRequestStatus('loading');
      const success = await onRequestBOM(bomParentQuery);
      if (success) {
          setBomRequestStatus('success');
          setTimeout(() => setBomRequestStatus('idle'), 3000);
      } else {
          setBomRequestStatus('idle');
      }
  };

  const bomResults = useMemo(() => {
    if (!displayedBomParent || !displayedBomQuantity) return [];
    return bomItems
        .filter(item => item.parentPart === displayedBomParent)
        .map(item => ({
            ...item,
            requiredQty: Math.ceil(item.quantity * displayedBomQuantity)
        }));
  }, [displayedBomParent, displayedBomQuantity, bomItems]);

  return (
    <div className="h-full animate-fade-in pb-20">
        <div className="max-w-7xl mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-700">
                        <div className="flex items-center gap-3 mb-8">
                            <div className="p-2 bg-teal-500/20 rounded-lg">
                                <ClipboardListIcon className="w-8 h-8 text-teal-400" />
                            </div>
                            <h2 className="text-2xl font-bold text-white uppercase tracking-tight">{t('bom_title')}</h2>
                        </div>

                        <div className="space-y-6">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_parent')}</label>
                                <PartNumberInput 
                                    parts={parts.map(p => p.value)} 
                                    value={bomParentQuery} 
                                    onInputChange={(val) => setBomParentQuery(val)} 
                                    onPartSelect={(val) => { if (val) setBomParentQuery(val); }} 
                                    placeholder={t('part_placeholder')} 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_qty')}</label>
                                <input 
                                    type="number" 
                                    inputMode="numeric"
                                    value={bomQuantity} 
                                    onChange={(e) => setBomQuantity(e.target.value)} 
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all text-base uppercase" 
                                    placeholder="500" 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_select_wp')}</label>
                                <select 
                                    value={bomSelectedWorkplace || ''} 
                                    onChange={(e) => setBomSelectedWorkplace(e.target.value)} 
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
                                >
                                    <option value="" className="font-sans normal-case">{t('workplace_placeholder')}</option>
                                    {workplaces.map(wp => <option key={wp.id} value={wp.value}>{wp.value}</option>)}
                                </select>
                            </div>

                            <button 
                                onClick={handleCalculateBOM} 
                                className="w-full h-14 bg-teal-600 hover:bg-teal-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transform transition-all active:scale-95 flex items-center justify-center gap-3 text-lg uppercase tracking-widest"
                            >
                                <ActivityIcon className="h-6 w-6" />
                                {t('bom_calc_btn')}
                            </button>

                            {bomParentQuery && bomResults.length === 0 && (
                                <button 
                                    onClick={handleRequestNewBOM}
                                    disabled={bomRequestStatus !== 'idle'}
                                    className={`w-full h-12 rounded-xl border text-base font-bold transition-all uppercase tracking-wide ${
                                        bomRequestStatus === 'success' ? 'bg-green-600 border-green-500 text-white' : 
                                        bomRequestStatus === 'loading' ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' :
                                        'bg-gray-800 border-gray-600 text-gray-300 hover:bg-gray-700'
                                    }`}
                                >
                                    {bomRequestStatus === 'loading' ? '...' : bomRequestStatus === 'success' ? t('bom_req_success') : t('bom_request_btn')}
                                </button>
                            )}
                        </div>
                    </div>

                    {bomResults.length > 0 && (
                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Komponenty' : 'Components'}</p>
                                <p className="text-3xl font-black text-white mt-1">{bomResults.length}</p>
                            </div>
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Zostáva' : 'Remaining'}</p>
                                <p className="text-3xl font-black text-orange-400 mt-1">{bomResults.length - clickedBOMTasks.size}</p>
                            </div>
                        </div>
                    )}
                </div>

                <div className="lg:col-span-8">
                    {bomResults.length > 0 ? (
                        <div className="bg-gray-800 rounded-2xl shadow-xl border border-gray-700 overflow-hidden flex flex-col h-full">
                            <div className="p-6 sm:p-8 border-b border-gray-700 flex justify-between items-center bg-gray-900/40">
                                <div>
                                    <h3 className="text-2xl font-black text-white font-mono uppercase tracking-tight">
                                        {displayedBomParent}
                                    </h3>
                                    <p className="text-base text-gray-500 mt-1">
                                        {t('bom_results')} <span className="text-teal-400 font-black">{displayedBomQuantity} ks</span>
                                    </p>
                                </div>
                                <button 
                                    onClick={() => handleCreateAllBOMTasks(bomResults)}
                                    className="bg-sky-600 hover:bg-sky-500 text-white px-8 py-3.5 rounded-xl text-base font-black shadow-lg transition-all active:scale-95 flex items-center gap-3 uppercase tracking-widest border-2 border-sky-500"
                                >
                                    🚀 {language === 'sk' ? 'Odoslať Všetko' : 'Send All'}
                                </button>
                            </div>

                            <div className="overflow-x-auto flex-grow custom-scrollbar">
                                <table className="w-full text-left">
                                    <thead className="bg-gray-900/50 text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-gray-700">
                                        <tr>
                                            <th className="py-5 px-8">{t('bom_child')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Spotreba/ks' : 'Usage/pc'}</th>
                                            <th className="py-5 px-8 text-right">{t('bom_req_qty')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Akcia' : 'Action'}</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-700/50">
                                        {bomResults.map((res) => {
                                            const isSent = clickedBOMTasks.has(res.childPart);
                                            return (
                                                <tr key={res.childPart} className={`transition-colors ${isSent ? 'bg-teal-500/5 opacity-60' : 'hover:bg-gray-700/30'}`}>
                                                    <td className="py-6 px-8">
                                                        <p className={`font-mono font-bold text-base ${isSent ? 'text-gray-500' : 'text-white'}`}>{res.childPart}</p>
                                                        <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">Standard Component</p>
                                                    </td>
                                                    <td className="py-6 px-8 text-center text-gray-400 font-mono text-sm">
                                                        {res.quantity}
                                                    </td>
                                                    <td className="py-6 px-8 text-right">
                                                        <span className={`text-xl font-black font-mono ${isSent ? 'text-gray-500' : 'text-teal-400'}`}>
                                                            {res.requiredQty} <span className="text-xs font-normal opacity-70">ks</span>
                                                        </span>
                                                    </td>
                                                    <td className="py-6 px-8 text-center">
                                                        <button 
                                                            onClick={() => !isSent && handleCreateBOMTask(res.childPart, res.requiredQty)}
                                                            disabled={isSent}
                                                            className={`inline-flex items-center justify-center h-14 w-14 rounded-xl transition-all shadow-lg border-2 ${
                                                                isSent ? 'bg-gray-700 text-teal-500 border-gray-600' : 'bg-teal-600/20 text-teal-400 hover:bg-teal-600 hover:text-white border-teal-500/30 active:scale-90'
                                                            }`}
                                                        >
                                                            {isSent ? <CheckCircleIcon className="w-8 h-8" /> : <PlusIcon className="w-8 h-8" />}
                                                        </button>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center bg-gray-800/50 rounded-2xl border-2 border-dashed border-gray-700 p-12 text-center shadow-inner">
                            <div className="w-24 h-24 bg-gray-700 rounded-full flex items-center justify-center mb-6 shadow-xl border border-gray-600">
                                <SearchIcon className="w-12 h-12 text-gray-500" />
                            </div>
                            <h3 className="text-2xl font-black text-gray-400 mb-3 uppercase tracking-tighter">{language === 'sk' ? 'Žiadne dáta na zobrazenie' : 'No data to display'}</h3>
                            <p className="text-gray-500 max-w-xs text-base font-medium leading-relaxed">{language === 'sk' ? 'Zadajte číslo výrobku a plánované množstvo pre výpočet potrebného materiálu.' : 'Enter product number and planned quantity to calculate required material.'}</p>
                        </div>
                    )}
                </div>

            </div>
        </div>
    </div>
  );
};

export default BOMScreen;

import React, { useState, useMemo, useEffect } from 'react';
import { Task } from '../../App';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface MissingItemsTabProps {
    tasks: Task[];
    onDeleteMissingItem: (id: string) => void;
    hasPermission: (perm: string) => boolean;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const ClockIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const AlertTriangleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>;
const ChevronDownIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" /></svg>;

const MissingItemsTab: React.FC<MissingItemsTabProps> = ({ tasks, onDeleteMissingItem, hasPermission }) => {
    const { t, language } = useLanguage();
    const [filterQuery, setFilterQuery] = useState('');
    const [currentTime, setCurrentTime] = useState(Date.now());
    const [expandedId, setExpandedId] = useState<string | null>(null);

    useEffect(() => {
        const interval = setInterval(() => setCurrentTime(Date.now()), 60000);
        return () => clearInterval(interval);
    }, []);

    const missingTasks = useMemo(() => {
        return tasks.filter(task => task.isMissing).sort((a, b) => {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        });
    }, [tasks]);

    const stats = useMemo(() => {
        const now = Date.now();
        const criticalLimit = 120 * 60 * 1000; 
        const criticalCount = missingTasks.filter(t => (now - (t.completedAt || t.createdAt || 0)) > criticalLimit).length;

        const reasons: Record<string, number> = {};
        missingTasks.forEach(t => { if(t.missingReason) reasons[t.missingReason] = (reasons[t.missingReason] || 0) + 1; });
        const topReason = Object.entries(reasons).sort((a,b) => b[1] - a[1])[0]?.[0] || '-';

        return {
            total: missingTasks.length,
            critical: criticalCount,
            topReason
        };
    }, [missingTasks]);

    const filteredItems = useMemo(() => {
        if (!filterQuery) return missingTasks;
        const q = filterQuery.toLowerCase();
        return missingTasks.filter(task => 
            (task.partNumber && task.partNumber.toLowerCase().includes(q)) ||
            (task.workplace && task.workplace.toLowerCase().includes(q)) ||
            (task.missingReportedBy && task.missingReportedBy.toLowerCase().includes(q)) ||
            (task.missingReason && task.missingReason.toLowerCase().includes(q)) ||
            (task.createdBy && task.createdBy.toLowerCase().includes(q))
        );
    }, [missingTasks, filterQuery]);

    const formatAgeing = (ts?: number) => {
        if (!ts) return null;
        const diffMs = currentTime - ts;
        const diffMin = Math.floor(diffMs / 60000);
        if (diffMin < 1) return t('miss_reported_just_now');
        return t('miss_reported_ago', { min: diffMin });
    };

    const getAgeingColor = (ts?: number) => {
        if (!ts) return 'text-slate-500';
        const diffMin = Math.floor((currentTime - ts) / 60000);
        if (diffMin > 120) return 'text-red-500 font-black animate-pulse';
        if (diffMin > 30) return 'text-orange-400 font-bold';
        return 'text-slate-400';
    };

    const getRowPriorityClass = (ts?: number) => {
        if (!ts) return 'border-transparent';
        const diffMin = Math.floor((currentTime - ts) / 60000);
        if (diffMin > 120) return 'border-l-red-600';
        if (diffMin > 30) return 'border-l-orange-500';
        return 'border-l-teal-500';
    };

    const formatDateShort = (ts?: number) => {
        if (!ts) return '-';
        const d = new Date(ts);
        return d.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit' }) + ' ' + 
               d.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') { alert('Export library missing.'); return; }
        const data = filteredItems.map(item => ({
            "ID": item.id,
            "Part_Number": item.partNumber || '-',
            "Workplace": item.workplace || '-',
            "Created_By": item.createdBy || '-',
            "Created_At": item.createdAt ? new Date(item.createdAt).toLocaleString('sk-SK') : '-',
            "Missing_Reason": item.missingReason || '-',
            "Reported_By": item.missingReportedBy || '-',
            "Reported_At": item.completedAt ? new Date(item.completedAt).toLocaleString('sk-SK') : '-',
            "Audited_By": item.auditedBy || '-',
            "Audited_At": item.auditedAt ? new Date(item.auditedAt).toLocaleString('sk-SK') : '-',
            "Audit_Result": item.auditResult || '-',
            "Audit_Note": item.auditNote || '-'
        }));
        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, "Raw_Data_Export");
        XLSX.writeFile(wb, `Missing_Items_Full_${new Date().toISOString().slice(0,10)}.xlsx`);
    };

    const handleDelete = (id: string) => {
        if (window.confirm(t('miss_delete_confirm'))) {
            onDeleteMissingItem(id);
        }
    }

    const toggleExpand = (id: string) => {
        setExpandedId(expandedId === id ? null : id);
    };

    const industrialCardBase = "bg-slate-900/50 border border-slate-800 p-6 rounded-2xl shadow-lg transition-all duration-300 hover:border-slate-700 overflow-hidden relative group";

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in px-2 md:px-0 text-slate-200">

            <div className="grid grid-cols-1 sm:grid-cols-3 gap-6">
                <div className={industrialCardBase}>
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">{t('miss_kpi_total')}</p>
                    <div className="flex items-end justify-between mt-4">
                        <span className="text-4xl font-black text-white">{stats.total}</span>
                        <div className="p-3 bg-teal-500/10 rounded-xl border border-teal-500/20 text-teal-400 shadow-inner">
                             <AlertTriangleIcon className="h-8 w-8" />
                        </div>
                    </div>
                </div>

                <div className={`${industrialCardBase} ${stats.critical > 0 ? 'border-red-900/50 ring-2 ring-red-500/10' : ''}`}>
                    {stats.critical > 0 && <div className="absolute inset-0 bg-red-600/5 animate-pulse"></div>}
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] relative z-10">{t('miss_kpi_critical')}</p>
                    <div className="flex items-end justify-between mt-4 relative z-10">
                        <span className={`text-4xl font-black ${stats.critical > 0 ? 'text-red-500' : 'text-slate-600'}`}>{stats.critical}</span>
                        <div className={`p-3 rounded-xl border transition-colors shadow-inner ${stats.critical > 0 ? 'bg-red-500/20 border-red-500/30 text-red-500 animate-pulse' : 'bg-slate-800 border-slate-700 text-slate-600'}`}>
                             <ClockIcon className="h-8 w-8" />
                        </div>
                    </div>
                </div>

                <div className={industrialCardBase}>
                    <p className="text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">{t('miss_kpi_top_reason')}</p>
                    <div className="flex items-end justify-between mt-4">
                        <span className="text-lg font-black text-amber-400 uppercase tracking-tight truncate max-w-[180px]">{stats.topReason}</span>
                        <div className="p-3 bg-amber-500/10 rounded-xl border border-amber-500/20 text-amber-500 shadow-inner">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
                        </div>
                    </div>
                </div>
            </div>

            <div className="bg-[#1a1f2e] rounded-2xl shadow-2xl border border-slate-800 overflow-hidden ring-1 ring-white/5">
                <div className="p-5 sm:p-8 bg-slate-900/40 border-b border-slate-800 flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="relative w-full md:w-[450px]">
                        <input 
                            type="text" 
                            value={filterQuery}
                            onChange={(e) => setFilterQuery(e.target.value)}
                            placeholder={t('task_search_placeholder')}
                            className="w-full h-12 bg-slate-800 border border-slate-700 rounded-xl px-4 pl-12 text-base text-white focus:outline-none focus:ring-2 focus:ring-teal-500/40 transition-all font-medium uppercase placeholder-gray-500 shadow-inner"
                        />
                        <svg xmlns="http://www.w3.org/2000/svg" className="absolute left-4 top-3.5 h-5 w-5 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                    </div>

                    <button onClick={handleExport} className="w-full md:w-auto bg-slate-800 hover:bg-slate-700 text-teal-400 border border-slate-700 px-8 py-4 rounded-xl text-sm font-black uppercase tracking-widest shadow-lg transition-all active:scale-95 flex items-center justify-center gap-3">
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        EXPORT RAW DATA
                    </button>
                </div>

                <div className="overflow-x-auto custom-scrollbar max-h-[750px]"> 
                    <table className="w-full text-left border-collapse min-w-[1100px] table-fixed">
                        <thead className="sticky top-0 z-20 shadow-md">
                            <tr className="bg-slate-950 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">
                                <th className="py-6 px-8 w-[280px]">DIEL & PRACOVISKO</th>
                                <th className="py-6 px-8 w-[250px]">DÔVOD</th>
                                <th className="py-6 px-8 w-[200px]">STARNUTIE</th>
                                <th className="py-6 px-8 w-[180px]">AUDIT VÝSLEDOK</th>
                                <th className="py-6 px-8 w-20"></th>
                                {hasPermission('perm_btn_delete') && <th className="py-6 px-8 w-20"></th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800">
                            {filteredItems.length > 0 ? (
                                filteredItems.map(item => {
                                    const reportTime = item.completedAt || item.createdAt || 0;
                                    const isNok = item.auditResult === 'NOK';
                                    const isExpanded = expandedId === item.id;

                                    return (
                                        <React.Fragment key={item.id}>
                                            <tr 
                                                onClick={() => toggleExpand(item.id)}
                                                className={`transition-all cursor-pointer border-l-[6px] ${getRowPriorityClass(reportTime)} ${isNok ? 'bg-red-500/5' : 'hover:bg-teal-500/[0.04]'}`}
                                            >
                                                <td className="py-6 px-8">
                                                    <div className="flex flex-col gap-2">
                                                        <span className="text-base font-black font-mono text-white bg-slate-800 px-4 py-1.5 rounded-lg border border-slate-700 w-fit shadow-md uppercase tracking-wide">
                                                            {item.partNumber}
                                                        </span>
                                                        <span className="text-xs font-black text-teal-400 uppercase tracking-[0.15em]">
                                                            {item.workplace}
                                                        </span>
                                                    </div>
                                                </td>

                                                <td className="py-6 px-8">
                                                    <span className="text-base font-black text-amber-500 tracking-tight leading-snug block">
                                                        {item.missingReason}
                                                    </span>
                                                </td>

                                                <td className="py-6 px-8">
                                                    <div className="flex items-center gap-3">
                                                        <div className={`w-2.5 h-2.5 rounded-full ${getAgeingColor(reportTime).includes('red') ? 'bg-red-500 shadow-[0_0_12px_rgba(239,68,68,0.8)] animate-pulse' : 'bg-teal-500'}`}></div>
                                                        <span className={`text-sm font-black uppercase tracking-widest ${getAgeingColor(reportTime)}`}>
                                                            {formatAgeing(reportTime)}
                                                        </span>
                                                    </div>
                                                </td>

                                                <td className="py-6 px-8">
                                                    {item.auditResult ? (
                                                        <span className={`px-4 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest w-fit border-2 ${item.auditResult === 'OK' ? 'bg-green-500/10 text-green-500 border-green-500/20 shadow-inner' : 'bg-red-600/10 text-red-500 border-red-600/20 shadow-inner'}`}>
                                                            {item.auditResult}
                                                        </span>
                                                    ) : (
                                                        <span className="text-xs text-slate-600 font-bold uppercase tracking-widest opacity-40 italic">Čaká na audit</span>
                                                    )}
                                                </td>

                                                <td className="py-6 px-8 text-center">
                                                    <ChevronDownIcon className={`w-6 h-6 text-slate-600 transition-transform duration-300 ${isExpanded ? 'rotate-180 text-teal-500' : ''}`} />
                                                </td>

                                                {hasPermission('perm_btn_delete') && (
                                                    <td className="py-6 px-8 text-center" onClick={(e) => e.stopPropagation()}>
                                                        <button onClick={() => handleDelete(item.id)} className="text-slate-700 hover:text-red-500 p-3 transition-all opacity-0 group-hover:opacity-100 hover:scale-110 active:scale-90 bg-slate-800/50 rounded-xl">
                                                            <TrashIcon className="h-6 w-6" />
                                                        </button>
                                                    </td>
                                                )}
                                            </tr>

                                            {isExpanded && (
                                                <tr className="bg-slate-950/40 border-l-[6px] border-slate-800 animate-fade-in shadow-inner">
                                                    <td colSpan={hasPermission('perm_btn_delete') ? 6 : 5} className="p-10">
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">

                                                            <div className="space-y-6">
                                                                <h4 className="text-xs font-black text-teal-500 uppercase tracking-[0.25em] border-b-2 border-teal-900/50 pb-3">História záznamu</h4>
                                                                <div className="grid grid-cols-2 gap-8">
                                                                    <div className="space-y-2">
                                                                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Vytvoril (Zadal):</p>
                                                                        <p className="text-base font-black text-slate-200 uppercase">{item.createdBy || '-'}</p>
                                                                        <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.createdAt)}</p>
                                                                    </div>
                                                                    <div className="space-y-2">
                                                                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Nahlásil (Missing):</p>
                                                                        <p className="text-base font-black text-slate-200 uppercase">{item.missingReportedBy || '-'}</p>
                                                                        <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.completedAt)}</p>
                                                                    </div>
                                                                </div>
                                                            </div>

                                                            <div className="space-y-6">
                                                                <h4 className="text-xs font-black text-amber-500 uppercase tracking-[0.25em] border-b-2 border-amber-900/50 pb-3">Detail auditu</h4>
                                                                {item.auditedBy ? (
                                                                    <div className="space-y-5">
                                                                        <div className="flex justify-between items-start">
                                                                            <div className="space-y-2">
                                                                                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Audítor:</p>
                                                                                <p className="text-base font-black text-amber-400 uppercase tracking-tight">{item.auditedBy}</p>
                                                                                <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.auditedAt || 0)}</p>
                                                                            </div>
                                                                            <div className={`px-6 py-3 rounded-2xl border-2 font-black text-sm tracking-[0.2em] shadow-lg ${item.auditResult === 'OK' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-600/10 text-red-500 border-red-600/20'}`}>
                                                                                AUDIT {item.auditResult}
                                                                            </div>
                                                                        </div>
                                                                        <div className="bg-slate-900/80 p-5 rounded-xl border border-slate-800 shadow-inner">
                                                                            <p className="text-[10px] font-black text-slate-600 uppercase tracking-widest mb-2">Interná poznámka:</p>
                                                                            <p className="text-sm text-slate-300 italic font-medium leading-relaxed">
                                                                                {item.auditNote || 'Bez poznámky'}
                                                                            </p>
                                                                        </div>
                                                                    </div>
                                                                ) : (
                                                                    <div className="py-10 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-2xl bg-slate-900/20">
                                                                        <ClockIcon className="w-10 h-10 text-slate-800 mb-3" />
                                                                        <p className="text-xs text-slate-700 font-black uppercase tracking-[0.15em]">Tento záznam ešte nebol auditovaný</p>
                                                                    </div>
                                                                )}
                                                            </div>

                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </React.Fragment>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={hasPermission('perm_btn_delete') ? 6 : 5} className="py-40 text-center text-slate-600">
                                        <div className="flex flex-col items-center gap-6">
                                            <div className="p-8 bg-slate-900 rounded-full border-2 border-slate-800 shadow-inner group-hover:scale-110 transition-transform duration-500">
                                                <svg xmlns="http://www.w3.org/2000/svg" className="h-20 w-20 text-slate-800" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                                            </div>
                                            <div className="space-y-2">
                                                <h4 className="text-2xl font-black text-slate-700 uppercase tracking-[0.3em]">{language === 'sk' ? 'VŠETKO KOMPLETNÉ' : 'ALL CLEAR'}</h4>
                                                <p className="text-xs font-bold text-slate-800 uppercase tracking-widest">{t('no_data')}</p>
                                            </div>
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>

                <div className="bg-slate-950 p-5 px-8 border-t border-slate-800 flex justify-between items-center shadow-inner">
                    <span className="text-[11px] text-slate-600 font-black uppercase tracking-widest">{filteredItems.length} {language === 'sk' ? 'POLOŽIEK NÁJDENÝCH' : 'ITEMS FOUND'}</span>
                    <span className="text-[11px] text-slate-700 font-mono italic">Industrial Deep Tracker • v1.4 Tablet Optimized</span>
                </div>
            </div>
        </div>
    );
};

export default MissingItemsTab;
